import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with 3 through streams (case 4 in partial sink)", () => {
  it("should correctly pipe source through 3 transforms and into a sink when using partial application", () => {
    const results: number[] = []

    // Create a simple source that emits 1, 2, 3
    const source = (end: any, cb: (end: any, data?: number) => void) => {
      let i = 0
      const values = [1, 2, 3]
      if (end) return cb(end)
      if (i >= values.length) return cb(true)
      // We need a stateful source
      cb(null, values[i++])
    }

    // Actually let's use a proper stateful source
    function createSource(values: number[]) {
      let i = 0
      return (end: any, cb: (end: any, data?: number) => void) => {
        if (end) return cb(end)
        if (i >= values.length) return cb(true)
        cb(null, values[i++])
      }
    }

    // Create a through stream that doubles values
    function doubler() {
      return (read: (end: any, cb: (end: any, data?: number) => void) => void) => {
        return (end: any, cb: (end: any, data?: number) => void) => {
          read(end, (end: any, data?: number) => {
            if (end) return cb(end)
            cb(null, data! * 2)
          })
        }
      }
    }

    // Create a sink that collects values
    function collectSink(arr: number[]) {
      return (read: (end: any, cb: (end: any, data?: number) => void) => void) => {
        function next() {
          read(null, (end: any, data?: number) => {
            if (end) return
            arr.push(data!)
            next()
          })
        }
        next()
      }
    }

    // This creates a partial sink with 3 through streams (length=3 in the partial function)
    // When called with a source, it becomes case 4: pull(read, ref[0], ref[1], ref[2])
    // Wait, let me re-read the code...
    // length is the number of args passed to the outer pull call
    // case 3 in switch means length=3, so: pull(read, ref[0], ref[1], ref[2])
    // The PLACEHOLDER is case 3, not case 4

    // Let me re-read: the mutation is at case 3 line
    // Original case 3: return pull(read, ref[0], ref[1], ref[2])
    // Mutated case 3: (empty - falls through to case 4)

    // So we need to test with length=3 (3 args to the partial pull)
    const partialSink = pull(doubler(), doubler(), collectSink(results))

    // partialSink is a function that takes a read (source)
    // When called, it should execute pull(read, doubler(), doubler(), collectSink(results))
    partialSink(createSource([1, 2, 3]))

    // Each value goes through two doublers: 1->2->4, 2->4->8, 3->6->12
    expect(results).toEqual([4, 8, 12])
  })
})
```

Looking at the mutation more carefully:

- The mutation is at `case 3:` in the switch statement
- Original `case 3:` returns `pull(read, ref[0], ref[1], ref[2])`
- Mutated `case 3:` is empty, so it falls through to `case 4:` which returns `pull(read, ref[0], ref[1], ref[2], ref[3])`

When `length=3` and we fall through to case 4, it tries to access `ref[3]` which is `undefined`. This would cause different behavior - the pull pipeline would receive an `undefined` as the 4th argument.

I need to create a test where a partial sink is created with exactly 3 arguments (so `length=3`), and verify the pipeline works correctly.

```typescript
import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull partial application with exactly 3 arguments", () => {
  it("should correctly execute pipeline when partial sink has 3 arguments (case 3)", () => {
    const results: number[] = []

    function createSource(values: number[]) {
      let i = 0
      return (end: any, cb: (end: any, data?: number) => void) => {
        if (end) return cb(end)
        if (i >= values.length) return cb(true)
        cb(null, values[i++])
      }
    }

    function adder(n: number) {
      return (read: (end: any, cb: (end: any, data?: number) => void) => void) => {
        return (end: any, cb: (end: any, data?: number) => void) => {
          read(end, (end: any, data?: number) => {
            if (end) return cb(end)
            cb(null, data! + n)
          })
        }
      }
    }

    function collectSink(arr: number[]) {
      return (read: (end: any, cb: (end: any, data?: number) => void) => void) => {
        function next() {
          read(null, (end: any, data?: number) => {
            if (end) return
            arr.push(data!)
            next()
          })
        }
        next()
      }
    }

    // Create a partial sink with exactly 3 arguments
    // This sets length=3 inside pull, triggering case 3 in the switch
    // Original: pull(read, ref[0], ref[1], ref[2]) - correct
    // Mutated: falls through to case 4: pull(read, ref[0], ref[1], ref[2], ref[3])
    //          where ref[3] is undefined, causing the pipeline to break
    const partialSink = pull(adder(10), adder(100), collectSink(results))

    // partialSink should be a function (partial application)
    expect(typeof partialSink).toBe("function")

    // Apply the source to the partial sink
    partialSink(createSource([1, 2, 3]))

    // Each value: 1+10+100=111, 2+10+100=112, 3+10+100=113
    expect(results).toEqual([111, 112, 113])
  })
})
